from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy.exc import IntegrityError
from collections import Counter
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///annotations.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class Annotation(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    image_id = db.Column(db.String(100), nullable=False)
    label = db.Column(db.String(100), nullable=False)
    annotator_id = db.Column(db.String(100), nullable=False)

db.create_all()

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.json
    if not all(k in data for k in ('image_id', 'label', 'annotator_id')):
        return jsonify({'error': 'Invalid data'}), 400

    new_annotation = Annotation(image_id=data['image_id'], label=data['label'], annotator_id=data['annotator_id'])
    try:
        db.session.add(new_annotation)
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return jsonify({'error': 'Annotation already exists'}), 409

    return jsonify({'message': 'Annotation added successfully'}), 201

@app.route('/aggregate/<image_id>', methods=['GET'])
def aggregate(image_id):
    annotations = Annotation.query.filter_by(image_id=image_id).all()
    if not annotations:
        return jsonify({'error': 'No annotations found'}), 404

    labels = [annotation.label for annotation in annotations]
    most_common_label = Counter(labels).most_common(1)[0][0]

    return jsonify({'image_id': image_id, 'aggregated_label': most_common_label}), 200

@app.route('/train', methods=['POST'])
def train():
    # Placeholder for model training logic
    return jsonify({'message': 'Training started'}), 202

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)), debug=False)